import pyotp
import qrcode
import os
import time

class TOTPAuthenticator:
    def __init__(self):
        self.secret = None

    def generate_secret(self):
        self.secret = pyotp.random_base32()
        return self.secret

    def create_qr_code(self, user_email):
        if not self.secret:
            raise ValueError("Secret not generated.")
        totp_uri = pyotp.totp.TOTP(self.secret).provisioning_uri(name=user_email, issuer_name="MyMFAApp")
        qr = qrcode.make(totp_uri)
        qr_file = f"{user_email}_qr.png"
        qr.save(qr_file)
        return qr_file

    def validate_totp(self, user_totp):
        if not self.secret:
            raise ValueError("Secret not generated.")
        totp = pyotp.TOTP(self.secret)
        return totp.verify(user_totp)

if __name__ == "__main__":
    user_email = input("Enter your email: ")
    authenticator = TOTPAuthenticator()
    
    # Generate TOTP secret
    secret = authenticator.generate_secret()
    print(f"Your TOTP secret is: {secret}")

    # Create QR code
    qr_code_file = authenticator.create_qr_code(user_email)
    print(f"QR code saved as: {qr_code_file}")

    # Validate TOTP code
    user_totp = input("Enter the TOTP code from your authenticator app: ")
